All augmented assignments modify the variable in place:

| Operator | Equivalent | Description |
|----------|------------|-------------|
| `x += y` | `x = x + y` | Add and assign |
| `x -= y` | `x = x - y` | Subtract and assign |
| `x *= y` | `x = x * y` | Multiply and assign |
| `x /= y` | `x = x / y` | Divide and assign |
| `x //= y` | `x = x // y` | Floor divide and assign |
| `x %= y` | `x = x % y` | Modulo and assign |
| `x **= y` | `x = x ** y` | Exponentiate and assign |
| `x @= y` | `x = x @ y` | Matrix multiply and assign |
| `x &= y` | `x = x & y` | Bitwise AND and assign |
| `x \|= y` | `x = x \| y` | Bitwise OR and assign |
| `x ^= y` | `x = x ^ y` | Bitwise XOR and assign |
| `x <<= y` | `x = x << y` | Left shift and assign |
| `x >>= y` | `x = x >> y` | Right shift and assign |

```jac
def example() {
    count = 0;
    total = 100.0;
    tax_rate = 1.08;
    value = 2;
    flags = 0b0000;
    NEW_FLAG = 0b0100;
    OLD_FLAG = 0b0010;
    bits = 0b1010;
    mask = 0b0011;
    register = 1;

    # Numeric augmented assignment
    count += 1;
    total *= tax_rate;
    value **= 2;

    # Bitwise augmented assignment
    flags |= NEW_FLAG;      # Set a flag
    flags &= ~OLD_FLAG;     # Clear a flag
    bits ^= mask;           # Toggle bits
    register <<= 4;         # Shift left
}
```

### 6 Null-Safe Operators

The `?` operator provides safe access to potentially null values, returning `None` instead of raising an error.

```jac
obj Profile {
    has settings: dict = {};
}

obj User {
    has profile: Profile | None = None;
}

def example(item: User | None, user: User | None) {
    # Without null-safe: raises AttributeError if item is None
    value = item.profile;

    # With null-safe: returns None if item is None
    value = item?.profile;

    # Chained - stops at first None
    result = user?.profile?.settings;
}
```

The `?[]` operator safely handles both `None` containers and invalid subscripts. It returns `None` instead of raising `IndexError`, `KeyError`, or `TypeError`:

```jac
def example(my_list: list | None, config: dict | None) {
    # Without null-safe: raises TypeError if list is None
    item = my_list[0];

    # With null-safe: returns None if list is None
    item = my_list?[0];

    # Works with dictionaries too
    value = config?["key"];

    # Also handles out-of-bounds indices
    items = [1, 2, 3];
    result = items?[10];         # None (no IndexError)

    # And missing dictionary keys
    data = {"a": 1};
    result = data?["missing"];   # None (no KeyError)
}
```

```jac
obj Data {
    def transform(param: str) -> Data {
        return self;
    }
    def format() -> str {
        return "formatted";
    }
}

def example(item: Data | None, data: Data | None) {
    # Returns None if item is None, doesn't call method
    result = item?.transform("x");

    # Chained with arguments
    output = data?.transform("param")?.format();
}
```

```jac
obj User {
    has name: str = "";
    has is_active: bool = True;
}

def example(user: User | None) {
    # Null-safe with fallback using or
    name = user?.name or "Anonymous";

    # In conditionals
    if user?.is_active {
        print(user);
    }
}
```

```jac
obj Item {
    has value: int = 0;
}

def example() {
    items = [Item(value=1), Item(value=-1), Item(value=2)];
    # The ? in filter comprehensions
    valid_items = items[?value > 0];  # Filter where value > 0
}
```

| Expression | When `obj` is `None` | When `obj` is valid |
|------------|---------------------|---------------------|
| `obj?.attr` | `None` | `obj.attr` |
| `obj?[key]` | `None` | `obj[key]` |
| `obj?.method()` | `None` | `obj.method()` |
| `obj?.a?.b` | `None` | `obj.a.b` (or `None` if `a` is `None`) |

### 7 Graph Operators (OSP)

Graph operators are fundamental to Object-Spatial Programming. They let you create connections between nodes (`++>`) and traverse the graph (`-->`). Unlike traditional object references, graph connections are first-class entities that can have their own types and attributes. Use these operators whenever you're building or navigating graph structures.

```jac
node Person {
    has name: str;
}

edge Friend {
    has since: int = 2020;
}

with entry {
    node1 = Person(name="Alice");
    node2 = Person(name="Bob");

    # Untyped connections
    node1 ++> node2;         # Forward
    node1 <++ node2;         # Backward
    node1 <++> node2;        # Bidirectional

    # Typed connections
    alice = Person(name="Alice");
    bob = Person(name="Bob");
    alice +>: Friend(since=2020) :+> bob;
}
```

```jac
node Item {
    has value: int = 0;
}

edge Link {
    has weight: int = 1;
}

walker Visitor {
    can visit with Item entry {
        # All outgoing edges
        neighbors = [-->];

        # All incoming edges
        sources = [<--];

        # Typed outgoing
        linked = [->:Link:->];

        # Filtered by edge attribute
        heavy = [->:Link:weight > 5:->];
    }
}
```

### 8 Pipe Operators

Pipe operators enable functional-style data transformation by passing results from one operation to the next. Instead of deeply nested function calls like `format(filter(transform(data)))`, you write `data |> transform |> filter |> format` -- reading naturally from left to right. Jac offers three pipe variants: standard pipes for functions, atomic pipes for controlling walker traversal order, and dot pipes for method chaining.

```jac
def double(x: int) -> int { return x * 2; }
def add_one(x: int) -> int { return x + 1; }

def example() {
    data = 5;

    # Forward pipe - data flows left to right
    result = data |> double |> add_one;

    # Equivalent to:
    result = add_one(double(data));
}
```

Atomic pipes feed a value into a callable, like `|>`/`<|`, but bind more tightly
(higher precedence). `:>` pipes left-to-right and `<:` right-to-left:

```jac
def double(x: int) -> int { return x * 2; }

with entry {
    r  = 5 :> double;    # 10
    r2 = double <: 5;    # 10
    print(r, r2);
}
```

!!! warning "`spawn` combined with a pipe operator does not currently work"
    Older material documents piping into a spawn to pick a traversal order --
    `start spawn :> Visitor()` or `start spawn |> Visitor()`. Both forms currently
    fail at runtime with `'Visitor' object is not callable`. Spawn a walker with
    the plain form instead (it works and runs the walker's entry abilities):

    ```jac
    node Item { has value: int = 0; }

    walker Visitor {
        can visit_item with Item entry { print(here.value); }
    }

    with entry {
        start = Item(value=1);
        start spawn Visitor();   # runs Visitor on `start`
    }
    ```

Dot pipes chain method calls:

```jac
obj Builder {
    has value: int = 0;

    def add(n: int) -> Builder {
        self.value += n;
        return self;
    }
    def double() -> Builder {
        self.value *= 2;
        return self;
    }
}

def example() {
    # Dot forward pipe
    result = Builder() .> add(5) .> double();

    # Equivalent to:
    result = Builder().add(5).double();
}
```

```jac
def example() {
    numbers = [1, 2, 3, 4, 5, 6, 7, 8];

    # Using lambdas in pipe chains
    result = numbers
        |> (lambda (x: list) { [i * 2 for i in x]; })
        |> (lambda (x: list) { [i for i in x if i > 10]; })
        |> sum;
}
```

| Operator | Name | Direction | Use Case |
|----------|------|-----------|----------|
| `\|>` | Forward pipe | Left to right | Function composition |
| `<\|` | Backward pipe | Right to left | Reverse composition |
| `:>` | Atomic forward | Left to right | Tight-binding forward pipe |
| `<:` | Atomic backward | Right to left | Tight-binding backward pipe |
| `.>` | Dot forward | Left to right | Method chaining |
| `<.` | Dot backward | Right to left | Reverse method chain |

### 9 The `by` Operator

The `by` operator is Jac's mechanism for delegation -- handing off work to an external system. Its most powerful use is with the `byllm` plugin, where `by llm` delegates function implementation to a language model. This enables "Meaning Typed Programming" where you declare *what* a function should do, and the LLM provides *how*. The operator is intentionally generic, allowing plugins to define custom delegation targets.

```jac
def example() {
    # Basic by expression
    result = "hello" by "world";

    # Chained by expressions (right-associative)
    result = "a" by "b" by "c";  # Parsed as: "a" by ("b" by "c")

    # With expressions
    result = (1 + 2) by (3 * 4);
}
```

When the `byllm` plugin is installed, `by` enables LLM delegation:

```jac
# Function implementation delegated to LLM
def summarize(text: str) -> str by llm();
sem summarize = "Summarize the given text in 2-3 sentences";

def translate(text: str) -> str by llm(model_name="gpt-4");
sem translate = "Translate the given text to French";

with entry {
    result = summarize("Hello world");
}
```

Use the **`sem` keyword** to attach semantic descriptions to functions, parameters, and fields. These descriptions are included in the compiler-generated prompt, giving the LLM additional context beyond what it can infer from names and types:

```jac
obj Ingredient {
    has name: str;
    has cost: float;
}
sem Ingredient.cost = "Estimated cost in USD";

def plan_shopping(recipe: str) -> list[Ingredient] by llm();
sem plan_shopping = "Generate a shopping list for the given recipe";
sem plan_shopping.recipe = "A description of the meal to prepare";
```

!!! tip
    Always use `sem` to provide context for `by llm()` functions. Docstrings are for human documentation and are not included in compiler-generated prompts.

### 10 The `as` Cast Operator

The `as` operator performs a type cast: `value as Type` tells the type checker to treat `value` as `Type`. It is *unchecked* and *type-erased* -- at runtime it does nothing and evaluates to `value` unchanged; only its static type changes. The semantics match `typing.cast`, but the syntax reads left-to-right and needs no import.

```jac
def example(raw: any) {
    count = raw as int;          # statically an int; no runtime check
    items = raw as list[str];    # cast to a generic type
}
```

Its primary use is as the escape hatch for the strict gradual-typing rule (see [The `any` Type and Gradual Typing](#the-any-type-and-gradual-typing)): an `any` value -- such as a walker report -- cannot flow silently into a declared concrete type, and the cast makes that re-typing explicit:

```jac
with entry {
    result = root spawn load_feed();
    tweets: list[TweetView] = result.reports[0] as list[TweetView];
}
```

**Precedence.** The cast binds just below the ternary and above every binary operator, so `a + b as T` parses as `(a + b) as T`. To cast a ternary, parenthesize it: `(x if c else y) as T`. Casts chain left-associatively, so `x as A as B` is `(x as A) as B`.

**Interaction with `with` / `except`.** Because `with <ctx> as <name>` and `except <type> as <name>` use `as` for their own alias, a top-level cast is not recognized in those positions -- parenthesize it instead: `with (x as T) as f`.

!!! warning
    The cast is unchecked. `"abc" as int` compiles without complaint; a wrong cast surfaces only as a later type error or a runtime failure. Use it when you genuinely know more than the checker, not to silence diagnostics blindly.

### 11 Operator Precedence

Complete precedence table from **lowest** (evaluated last) to **highest** (evaluated first):

| Precedence | Operators | Associativity | Description |
|------------|-----------|---------------|-------------|
| 1 (lowest) | `lambda` | - | Lambda expression |
| 2 | `if else` | Right | Ternary conditional |
| 3 | `as` | Left | Type cast |
| 4 | `by` | Right | By operator (LLM delegation) |
| 5 | `:=` | Right | Walrus operator |
| 6 | `or` | Left | Logical OR |
| 7 | `and` | Left | Logical AND |
| 8 | `not` | - | Logical NOT (unary) |
| 9 | `in`, `not in`, `is`, `is not`, `<`, `<=`, `>`, `>=`, `!=`, `==` | Left | Comparison/membership |
| 10 | `\|` | Left | Bitwise OR |
| 11 | `^` | Left | Bitwise XOR |
| 12 | `&` | Left | Bitwise AND |
| 13 | `<<`, `>>` | Left | Bit shifts |
| 14 | `\|>`, `<\|` | Left | Pipe operators |
| 15 | `+`, `-` | Left | Addition, subtraction |
| 16 | `*`, `/`, `//`, `%`, `@` | Left | Multiplication, division, modulo, matmul |
| 17 | `+x`, `-x`, `~` | - | Unary plus, minus, bitwise NOT |
| 18 | `**` | Right | Exponentiation |
| 19 | `await` | - | Await expression |
| 20 | `spawn` | Left | Walker spawn |
| 21 | `:>`, `<:` | Left | Atomic pipes |
| 22 | `++>`, `<++`, connection ops | Left | Graph connection |
| 23 (highest) | `x[i]`, `x.attr`, `x()`, `x?.attr` | Left | Subscript, attribute, call |

```jac
def f(x: int) -> int { return x + 1; }
def g(x: int) -> int { return x * 2; }

def example() {
    a = 1; b = 2; c = 3; cond = True;

    # Ternary binds loosely
    x = a if cond else b + 1;   # x = a if cond else (b + 1)

    # Logical operators
    x = a or b and c;           # x = a or (b and c)
    x = not a and b;            # x = (not a) and b

    # Comparison chaining
    x = 5;
    valid = 0 < x < 10;         # (0 < x) and (x < 10)

    # Arithmetic
    x = a + b * c;              # x = a + (b * c)
    x = a ** b ** c;            # x = a ** (b ** c)

    # Bitwise
    x = a | b & c;              # x = a | (b & c)
    x = a << 2 + 1;             # x = a << (2 + 1)

    # Pipe operators
    result = a |> f |> g;       # result = g(f(a))

    # Walrus in condition
    items = [1, 2, 3];
    if (n := len(items)) > 2 { print(n); }
}
```

`and` and `or` use short-circuit evaluation

In Python or TypeScript, branching between specialists normally requires three pieces: a classifier prompt that picks a label, a dispatch dictionary that maps each label to a handler function, and the handler functions themselves with their own prompts. Adding a new specialist means updating these three pieces. In the Jac code above, each specialist is a node with a `description` field (`HardwareExpert`, `SoftwareExpert`, `AIExpert`). The line `visit [-->] by llm(incl_info={"User query": self.query})` lets the model read each connected node's description and pick which one to visit. Adding a new specialist means adding one node with a description, without touching a prompt or a dispatch table.

```jac
enum Quality { GOOD, NEEDS_IMPROVEMENT }

obj Review {
    has quality: Quality;
    has weaknesses: list[str];
    has suggestion: str;
}

edge RetryEdge {
    has reason: str = "Verdict was NEEDS_IMPROVEMENT";
    has max_retries: int = 3;
}

node Draft    { def run(topic: str) -> str by llm(); }
node Evaluate { def run(draft: str, topic: str) -> Review by llm(); }
node Revise   { def run(draft: str, feedback: str) -> str by llm(); }
node Approved {}

sem Draft.run    = "Write a first-draft tutorial section on the topic.";
sem Evaluate.run = "Critique the draft as a tutorial on the topic and return a typed verdict.";
sem Revise.run   = "Rewrite the draft to address the feedback.";

walker TutorialWriter {
    has topic: str;
    has draft: str = "";
    has feedback: str = "";
    has version: int = 1;

    can begin with Root entry {
        visit [-->];
    }

    can do_draft with Draft entry {
        self.draft = here.run(self.topic);
        visit [-->];
    }

    can do_evaluate with Evaluate entry {
        review = here.run(self.draft, self.topic);
        if review.quality == Quality.GOOD {
            visit [-->][?:Approved];
        } else {
            self.feedback = f"{review.weaknesses}. {review.suggestion}";
            visit [->:RetryEdge:->];
        }
    }

    can do_revise with Revise entry {
        self.version += 1;
        self.draft = here.run(self.draft, self.feedback);
        visit [-->];
    }
}

with entry {
    draft = Draft();   eval_n = Evaluate();
    revise = Revise(); done   = Approved();

    root ++> draft ++> eval_n;
    eval_n ++> done;
    eval_n +>:RetryEdge:+> revise;
    revise ++> eval_n;

    root spawn TutorialWriter(topic="How cache coherence works in multicore processors");
}
```

In Python or TypeScript, this normally takes a `while` loop with an exit condition that matches against a substring in the model's reply (`if 'GOOD' in response: break`) and a magic number for the maximum retry count. The intent of the loop, that this is a critique-and-revise cycle, lives only in a comment. In the Jac code above, the loop is a named edge `RetryEdge` between the `Evaluate` and `Revise` nodes, declared as `eval_n +>:RetryEdge:+> revise`. A reader scanning the graph immediately sees what kind of loop this is. The exit condition rides on a typed `Quality` verdict returned by `Evaluate`, not on a string match, and the maximum retry count is a typed field on the edge rather than a magic number in a function body.

```jac
def search_papers(query: str) -> str { return f"papers on '{query}'"; }
def get_citations(paper_id: str) -> int { return 1247; }

walker HardwareResearcher {
    has topic: str;
    has result: str = "";
    def investigate(topic: str) -> str by llm(tools=[search_papers, get_citations]);
    can start with Root entry {
        self.result = self.investigate(self.topic);
    }
}
sem HardwareResearcher.investigate = "Research the topic from a hardware angle using the tools.";

walker SoftwareResearcher {
    has topic: str;
    has result: str = "";
    def investigate(topic: str) -> str by llm(tools=[search_papers, get_citations]);
    can start with Root entry {
        self.result = self.investigate(self.topic);
    }
}
sem SoftwareResearcher.investigate = "Research the topic from a software angle using the tools.";

walker AIResearcher {
    has topic: str;
    has result: str = "";
    def investigate(topic: str) -> str by llm(tools=[search_papers, get_citations]);
    can start with Root entry {
        self.result = self.investigate(self.topic);
    }
}
sem AIResearcher.investigate = "Research the topic from an AI/ML angle using the tools.";

walker SurveyAgent {
    has topic: str;
    has response: str = "";
    def synthesize(
        topic: str,
        hw: HardwareResearcher,
        sw: SoftwareResearcher,
        ai: AIResearcher
    ) -> str by llm();

    can start with Root entry {
        hw_task = flow root spawn HardwareResearcher(topic=self.topic);
        sw_task = flow root spawn SoftwareResearcher(topic=self.topic);
        ai_task = flow root spawn AIResearcher(topic=self.topic);

        hw: HardwareResearcher = (wait hw_task) as HardwareResearcher;
        sw: SoftwareResearcher = (wait sw_task) as SoftwareResearcher;
        ai: AIResearcher = (wait ai_task) as AIResearcher;

        self.response = self.synthesize(self.topic, hw, sw, ai);
    }
}
sem SurveyAgent.synthesize = "Combine the hardware, software, and AI research notes into one survey.";

with entry {
    root spawn SurveyAgent(topic="Efficient inference for large language models");
}
```

In Python or TypeScript, parallel work usually collapses into either a single bloated prompt holding all the tools and asking the model to manage them itself, or a hand-rolled threadpool with manual result merging. In the Jac code above, `SurveyAgent` spawns three independent walkers (`HardwareResearcher`, `SoftwareResearcher`, `AIResearcher`) using `flow root spawn`, then collects their results with `wait`. Each researcher carries its own scoped tool list and its own context, so three focused prompts run concurrently rather than one bloated prompt holding nine tools. The synthesis step `self.synthesize(...)` only runs after all three workers have completed.

Together, these four patterns address the third of our problems: workflows that live inside a prompt as a string and cannot be verified or observed by the surrounding code. In Jac, the workflow is the graph itself, where the steps, branches, retries, and parallelism are all visible as connections between nodes. The seven patterns, three for what happens inside an iteration and four for how iterations connect, cover what every agent codebase rebuilds by hand in Python or TypeScript.

## The Takeaway

The seven Mind and Flow patterns map directly onto the three problems we started with.

| The problem | How Jac addresses it |
|---|---|
| **The same intent written twice.** Tool schemas and structured-output classes have to be declared in code and described again in prompts or JSON specs, with nothing keeping the two halves in sync. | The Mind patterns keep intent in one place. The function signature itself becomes the prompt that the model receives. The return type defines the schema for structured output. Tools are simply ordinary functions whose signatures the runtime introspects. byLLM uses all of this to build the prompt automatically. |
| **Control flow lives in prose.** Workflows, routing decisions, retry conditions, and parallelism end up inside system prompts as English, where no code can verify whether the model followed them. | The Flow patterns express workflows as graph structure. Pipelines, branches, retries, and parallel fan-outs are all visible as connections between nodes, observable by the runtime and readable by the developer. |
| **The plumbing is rebuilt every project.** Every team writes its own ReAct loop, its own validation-and-retry, its own router, and its own threadpool, and ships its own bugs in them. | byLLM and OSP handle this plumbing in the runtime. The tool-use loop, the validation-and-retry, the routing, and the parallel fan-out are features of the language rather than code every team writes from scratch. |

Those languages weren't chosen because they fit agents. They were chosen for ecosystem maturity. The cost is that every team rebuilds the same supporting code, and the codebase bloats around the missing patterns.<|im_end|>

# You just have to learn 4 things to know Object-Spatial Programming

Most programming paradigms ask you to learn dozens of concepts, patterns, and best practices. Object-Spatial Programming (OSP) is different. At its core, there are really just **four fundamental concepts** you need to understand. Master these four things, and you'll have unlocked an entirely new way of thinking about computation—one that's particularly well-suited for modern applications dealing with complex relationships, graph structures, and distributed data.

This article will teach you the complete model of Object-Spatial Programming through these four conceptual buckets. Each builds naturally on the last, and by the end, you'll understand why OSP represents a genuine paradigm shift in how we structure programs.

## What is Object-Spatial Programming?

Before we dive into the four concepts, let's establish what makes Object-Spatial Programming fundamentally different from traditional Object-Oriented Programming (OOP).

**Traditional OOP:**
```
Data sits still → You bring computation to the data
(Call methods on objects)
```

**Object-Spatial Programming:**
```
Data is arranged in space → You send computation to travel through the data
(Walkers visit nodes in a graph)
```

- **OOP**: You're at home, you call restaurants and have food delivered to you
- **OSP**: You send a robot out to visit different restaurants and collect food

Both get you fed, but they work fundamentally differently! In OSP, computation is **mobile** and data is **spatial**.

## Concept 1: The Spatial Object Model (Nodes & Edges)

The first thing you need to understand is how objects are structured in Object-Spatial Programming. Instead of thinking about isolated objects, you think about **objects arranged in space with explicit relationships**.

> **🔑 Core Insight:** Everything in OSP is built on classes. `node`, `edge`, and `walker` are **not** new primitive types—they're classes that inherit all OOP capabilities (methods, properties, inheritance, polymorphism) **and add** spatial/traversal semantics. This means OSP extends OOP rather than replacing it.

| Type | What It Is | Purpose | Traditional Analogy |
|------|------------|---------|-------------------|
| `node` | **Class with spatial semantics** | Data locations that can be connected in graphs | Houses on a map |
| `edge` | **Class representing relationships** | First-class connections between nodes | Roads between houses |

**Key point:** Nodes and edges are full-featured classes with methods, inheritance, and properties—PLUS spatial connection capabilities.

**Important: Nodes are classes!** They have all the semantics of regular classes (methods, inheritance, polymorphism) PLUS the ability to be connected in spatial graphs.

```jac
node Person {
    has name: str;
    has age: int;

    def greet -> str {
        return f"Hello, I'm {self.name}!";
    }

    def celebrate_birthday {
        self.age += 1;
        print(f"{self.name} is now {self.age}!");
    }
}

with entry {
    alice = Person(name="Alice", age=25);
    bob = Person(name="Bob", age=30);

    print(alice.greet());
    alice.celebrate_birthday();
    print(bob.greet());
}
```

At this point, nodes work exactly like regular classes. The spatial magic happens when we connect them...

This is where OSP diverges from traditional OOP. You can **directly connect** nodes using spatial operators:

```jac
node Person {
    has name: str;
}

with entry {
    alice = Person(name="Alice");
    bob = Person(name="Bob");
    charlie = Person(name="Charlie");

    # Build the graph structure
    alice ++> bob;      # Alice → Bob
    alice ++> charlie;  # Alice → Charlie
    bob ++> charlie;    # Bob → Charlie

    root ++> alice;

    # Query connections
    connections = [alice -->];
    print(f"Alice is connected to {len(connections)} person(s)");
}
```

```mermaid
graph TD
    Alice --> Bob
    Alice --> Charlie
    Bob --> Charlie
```

| Operator | Direction | Example | Result |
|----------|-----------|---------|--------|
| `++>` | Forward | `alice ++> bob;` | alice → bob |
| `<++` | Backward | `alice <++ bob;` | bob → alice |
| `<++>` | Both ways | `alice <++> bob;` | alice ↔ bob |

Here's what makes OSP truly revolutionary: **relationships are first-class objects** with their own types and properties!

**Important: Edges are also classes!** Like nodes, edges have all the semantics of regular classes—they can have methods, properties, and behavior—PLUS they represent connections in the graph.

```jac
node Person {
    has name: str;
}

edge Friend {
    has since: int;
    has strength: int = 5;

    def years_of_friendship(current_year: int) -> int {
        return current_year - self.since;
    }

    def is_strong -> bool {
        return self.strength >= 7;
    }
}

edge Coworker {
    has department: str;
}

with entry {
    alice = Person(name="Alice");
    bob = Person(name="Bob");
    charlie = Person(name="Charlie");

    root ++> alice;
    alice +>:Friend(since=2015, strength=9):+> bob;
    alice +>:Coworker(department="Engineering"):+> charlie;

    friends = [alice ->:Friend:->];
    coworkers = [alice ->:Coworker:->];
    print(f"Alice has {len(friends)} friend(s) and {len(coworkers)} coworker(s)");
}
```

**This is a paradigm shift!** In traditional OOP, relationships are just data in lists or dictionaries. In OSP, relationships are **classes in their own right** that exist in the spatial model and can have methods, properties, and behavior.

```mermaid
graph LR
    Alice -->|Friend since 2015<br/>strength: 9| Bob
    Alice -->|Coworker<br/>dept: Engineering| Charlie
```

Once you've built a graph structure, you can query it using **edge references** with square brackets:

```jac
node Person {
    has name: str;
}

edge Friend {
    has since: int;
}

with entry {
    alice = Person(name="Alice");
    bob = Person(name="Bob");
    charlie = Person(name="Charlie");

    root ++> alice;
    alice +>:Friend(since=2015):+> bob;
    alice +>:Friend(since=2020):+> charlie;

    all_connections = [alice -->];
    print(f"Total connections: {len(all_connections)}");

    friends = [alice ->:Friend:->];
    print(f"Friends: {len(friends)}");

    old_friends = [alice ->:Friend:since < 2018:->];
    print(f"Friends since before 2018: {len(old_friends)}");
}
```

| Pattern | Direction | Type Filter | Example |
|---------|-----------|-------------|---------|
| `[node -->]` | Outgoing | Any | All outgoing connections |
| `[node <--]` | Incoming | Any | All incoming connections |
| `[node <-->]` | Both | Any | All connections |
| `[node ->:Type:->]` | Outgoing | Specific | Specific edge type |
| `[node ->:Type:property > 5:->]` | Outgoing | Filtered | With property filter |

```jac
obj Person {
    has name: str;
    has connections: list = [];
}

obj Connection {
    has conn_type: str;
    has target: object;
}

def find_friends(person: Person) -> list {
    friends = [];
    for connection in person.connections {
        if connection.conn_type == "friend" {
            friends.append(connection.target);
        }
    }
    return friends;
}

with entry {
    alice = Person(name="Alice");
    bob = Person(name="Bob");

    conn = Connection(conn_type="friend", target=bob);
    alice.connections.append(conn);

    friends = find_friends(alice);
    print(f"Alice's friends: {len(friends)}");
}
```

```jac
# Concise, declarative, type-safe
node Person {
    has name: str;
}

edge Friend {}

with entry {
    alice = Person(name="Alice");
    bob = Person(name="Bob");

    root ++> alice;
    alice +>:Friend:+> bob;

    friends = [alice ->:Friend:->];
    print(f"Alice has {len(friends)} friend(s)");
}
```

**Key advantages:**
1. **Natural representation**: Relationships are explicit in the structure
2. **Type safety**: Edges have their own types and properties
3. **Declarative queries**: Express what you want, not how to get it
4. **Visual clarity**: The code structure mirrors the data structure

Since nodes and edges are classes, they support all standard OOP features:

```jac
